		/* -------------- DROP MENU ----------------- */

		.sf-menu,
		.sf-menu * {
			margin: 0;
			padding: 0;
		}

		.sf-menu ul {
			position: absolute;
			top: -999em;
			width: 220px;
			z-index: 750;
		}

		.sf-menu ul li {
			width: 100%;
			padding: 0;
			margin: 0;
		}

		.sf-menu li {
			float: left;
			position: relative;
			z-index: 800;
		}

		.sf-menu a {
			display: block;
			position: relative;
		}

		.sf-menu li:hover {
			visibility: inherit;
		}

		.sf-menu li:hover ul,
		.sf-menu li.sfHover ul {
			left: 0;
			top: 39px;
			z-index: 99;
			border: 1px solid #909090;
			border-top: 1px solid #000;
		}

		ul.sf-menu li:hover li ul,
		ul.sf-menu li.sfHover li ul {
			top: -999em;
		}

		ul.sf-menu li li:hover ul,
		ul.sf-menu li li.sfHover ul {
			/*left: 10em;*/
			top: 0;
		}

