		.ui-datepicker td span,
		.ui-datepicker td a {
			display: block;
			padding: 0;
			line-height: 21px;
		}

		img.ui-datepicker-trigger {
			vertical-align: middle;
			margin-left: -29px;
			margin-right: 20px;
			margin-top: -6px;
