		}

		/* DL DT */

		dl {
			border-bottom: 1px solid #B2B2B2;
			display: block;
			line-height: 15px;
			margin: 0;
			padding: 7px 0 4px;
		}

		dl.last {
			border-bottom: medium none;
			padding: 4px 0 7px;
		}

