* --------------------------------------------------------
*/

		table tr th {
			color: #232323;
		}

		table tr.ligne_non_lu td {
			font-weight: bold;
		}

		/* -------- TABLE HEADER ---------- */

		thead td.percent {
			padding-bottom: 0;
			border-top: 1px solid #E5E5E8;
		}

		thead td.percent div {
			float: left;
			height: 12px;
		}

		thead td .h_up {
			border-bottom: 2px solid #4CA102;
			padding-bottom: 4px;
		}

		thead td .h_stagne {
			border-bottom: 2px solid #929292;
			padding-bottom: 4px;
		}

		thead td .h_down {
			border-bottom: 2px solid #EF0000;
			padding-bottom: 4px;
		}

		/*
* -------- END TABLE HEADER --------
