* ----------------- TABLE des divs BLOCK---------
* ----------------- TODO: Tri à faire ^^---------
* -----------------------------------------------
*/

		.block table thead th,
		.block table td {
			padding: 11px 10px;
			font-size: 12px;
		}

		.block table th {
			text-align: left;
			/*pour que ie 8 ne centre pas */
			font-size: 12px;
			font-weight: 500;
		}

		.block table th.col_right {
			text-align: right;
		}

		.block table {
			width: 100%;
		}

		/* ACTU */

		.block table.actu td {
			padding-bottom: 10px;
			padding-top: 10px;
			font-size: .91em;
		}

		/*
* -------- FIELDS --------------
