*/

		.block table.last td,
		.block table td.last {
			border-bottom: 0;
		}

		.block table tr.important td {
			font-weight: bold;
			/*background-color: #EFEFEF;*/
		}

		.block table td a {
			color: #232323;
		}

		.block table td a:hover {
			text-decoration: none;
		}

		.block table td.evol,
		.block table td.evol_up,
		.block table td.evol_down,
		.block table td.evol_stagne,
		.block table td.numb,
		.block table td.date,
