			text-align: right;
			white-space: nowrap;
		}

		.block table th.evol,
		thead th.numb,
		thead th.date {
			text-align: right;
		}

		.block table td.txt {
			text-align: left;
			background-image: none;
		}

		.block table td.bold {
			font-weight: bold;
		}

		.block table th.centrage {
			text-align: center;
