* FORM global
*/

		select,
		textarea,
		input[type="text"],
		input[type="password"],
		input#inputMontantRepartition,
		input#inputMontantTotal,
		input#lettres,
		input#inputRepartitionApresArbitrage,
		input.s_style01,
		input#isin2,
		input#isin3 {
			border: 1px solid #D0D0D0;
			background: #FFFFFF;
			padding: 0 10px;
			border-radius: 5px;
			box-sizing: border-box;
			height: 38px;
			line-height: 38px;
		}

		input[size="8"],
		input[size="10"] {
			width: 90px;
		}

		input[size="46"] {
			width: 340px;
		}

		input[size="3"] {
			width: 60px;
		}

		input[size="2"] {
			width: 40px;
		}

		input[size="29"] {
			width: 290px;
		}

		input[type="text"][name^="montant"],
		select#selectNbrPage {
			margin-right: 7px;
		}

		input.disabledField,
		input.shortFieldOst:disabled,
		input[type="text"]:disabled,
		input[type="password"]:disabled,
		input.s_style01:disabled,
		input#isin2.disabledField,
		input#isin3.disabledField {
			border: 1px solid #E9E9E9;
			background-color: #F0F0F0;
			padding: 0 10px;
			border-radius: 5px;
			color: #959595;
			box-sizing: border-box;
			height: 38px;
			line-height: 38px;
			opacity: 1;
		}

		select {
			background-image:
				/*savepage-url=../images/picto/chevron.svg*/
				url();
			background-repeat: no-repeat;
			background-position: center right;
			-webkit-appearance: none;
			-moz-appearance: none;
			appearance: none;
			padding-right: 30px;
			line-height: 36px;
			opacity: 1;
		}

		select:disabled {
			border: 1px solid #E9E9E9 !important;
			background-color: #F0F0F0 !important;
			color: #959595 !important;
		}

		select::-ms-expand {
			display: none;
		}

		textarea {
			height: auto;
			line-height: normal;
			padding: 10px;
		}

		select:focus,
		textarea:focus,
		input[type="text"]:focus,
		input[type="password"]:focus,
		input#lettres:focus,
		input.s_style01:focus,
		input#isin2:focus,
		input#isin3:focus {
			outline: none !important;
			border: 2px solid #88C648 !important;
		}

