	<style data-savepage-href="/datas/css/bourse.css" type="text/css" media="all">
		/* --------------------------------------------------------------
* -------------------- SPECIFIC BOURSE CODE --------------------
* --------------------------------------------------------------
* -------------------- HOME --------------------
* @dependance : global.css
*/
		/*savepage-import-url=./composants/checkboxConsent.css*/

		.checkbox-container {
			--border-width-none: 0;
			--themes-light-theme-default-accent3: #4A4A49;
			--themes-light-background-alternate: #F2F4FA;
			--themes-light-theme-selected-main: #0076FF;
			--themes-light-border-focus: #96C6FF;
			--themes-light-border-default: #D0D0D0;
			--themes-light-background-default: #FFFFFF;
			--border-radius-s: 0.3125rem;
			--border-width-s: 0.0625rem;
			--border-width-m: 0.125rem;
			--spacing-xs: 0.25rem;
			--spacing-s: 0.5rem;
			--spacing-sm: 0.75rem;
			--spacing-m: 1rem;
			--spacing-ml: 1.25rem;
			--spacing-l: 1.5rem;
			--spacing-xl: 2rem;
			--spacing-xxl: 2.5rem;
			border-radius: var(--border-radius-s);
			border-style: solid;
			position: relative;
			user-select: none;
			background-color: var(--themes-light-background-default);
			border-color: var(--themes-light-border-default);
			border-width: var(--border-width-s);
			cursor: pointer;
			display: inline-block;
			min-width: 17.5rem;
			margin-top: var(--spacing-xl);
			padding: 1.1875rem 0.75rem;
		}

		/* Hide the default checkbox */

		.checkbox-container input.custom-checkbox {
			position: absolute;
			opacity: 0;
			cursor: pointer;
			height: 0;
			width: 0;
		}

		.checkbox-container:focus-within:has(:focus-visible) {
			outline: var(--themes-light-border-focus) solid 3px;
			/* Adjust this to the px2rem value */
			outline-offset: 3px;
			/* Adjust this to the px2rem value */
		}

		.checkbox-container.full-width {
			display: flex;
		}

		.checkbox-container.checked {
			border-color: var(--themes-light-theme-selected-main);
			border-width: var(--border-width-m);
			padding: 18px 11px;
			/* Adjust this to the px2rem value */
		}

		.checkbox-container.checked:hover {
			border-color: var(--themes-light-theme-selected-main);
		}

		.checkbox-container.consent.outlined {
			background-color: var(--themes-light-background-alternate);
		}

		.checkbox-container.disabled {
			cursor: default;
			opacity: 0.5;
			pointer-events: none;
		}

		.checkbox-container.checkbox-only {
			border-width: var(--border-width-none);
			min-height: 0;
			min-width: 0;
			padding: 0;
		}

		.checkbox-container.checkbox-only:hover {
			border-width: var(--border-width-none);
			padding: 0;
		}

		.checkbox-container:not(.outlined) {
			border-width: var(--border-width-none);
			min-height: 0;
			padding: 0;
		}

		.checkbox-container:hover {
			border-width: var(--border-width-m);
			border-color: var(--themes-light-theme-default-accent3);
			padding: 18px 11px;
			/* Adjust this to the px2rem value */
		}

		/* Create a custom checkmark */

		#checkbox-content {
			position: relative;
			display: grid;
			grid-template-columns: 2% 1fr;
			grid-template-rows: 1fr;
			grid-column-gap: 16px;
			grid-row-gap: 0px;
		}

		.checkbox-contentLeft {
			grid-area: 1 / 1 / 2 / 2;
		}

		.checkbox-contentRight {
			grid-area: 1 / 2 / 2 / 3;
		}

		.checkbox-container .checkmark {
			--checkmark-size: 16px;
			position: absolute;
			top: 0;
			left: 0;
			height: var(--checkmark-size);
			width: var(--checkmark-size);
			background-color: white;
			border-radius: var(--border-radius-xs);
			border: var(--border-width-s) solid var(--themes-light-border-default);
			margin: 0 1rem 0 -0.1875rem;
		}

		/* When the checkbox is checked, add a background color */

		.checkbox-container input.custom-checkbox:checked~.checkmark {
			background-color: var(--themes-light-theme-selected-main);
			border-color: var(--themes-light-theme-selected-main);
		}

		/* Create the checkmark/indicator (hidden when not checked) */

		.checkbox-container .checkmark:after {
			content: "";
			position: absolute;
			display: none;
		}

		/* Show the checkmark when checked */

		.checkbox-container input.custom-checkbox:checked~.checkmark:after {
			display: block;
		}

		/* Style the checkmark/indicator */

		.checkbox-container .checkmark:after {
			left: 5px;
			top: 0px;
			width: 4px;
			height: 10px;
			border: solid white;
			border-width: 0 2px 2px 0;
			transform: rotate(45deg);
		}

		#validerform_tarifs:disabled {
			cursor: default;
			opacity: 0.5;
		}

